// ═══════════════════════════════════════════════════
// EMPIRE BOT — MASTER ROUTER
// Extracts route + user data into flat fields
// Switch node matches on $json._route
// ═══════════════════════════════════════════════════
const update = $input.first().json;
let route = 'unknown';
let chat_id = '';
let first_name = '';
let telegram_id = '';
let username = '';
let callback_data = '';

if (update.callback_query) {
  callback_data = (update.callback_query.data || '').trim();
  chat_id = update.callback_query.message.chat.id;
  first_name = update.callback_query.from.first_name || '';
  telegram_id = String(update.callback_query.from.id);
  username = update.callback_query.from.username || '';

  // Quiz answers: q1_0, q2_1, etc.
  if (callback_data.match(/^q\d+_/)) {
    route = 'quiz_answer';
  } else {
    route = callback_data.toLowerCase();
  }
} else if (update.message) {
  const text = (update.message.text || '').trim();
  chat_id = update.message.chat.id;
  first_name = update.message.from.first_name || '';
  telegram_id = String(update.message.from.id);
  username = update.message.from.username || '';

  if (text === '/start' || text === '/menu') {
    route = 'start';
  } else if (text === '/stop') {
    route = 'stop';
  } else {
    route = 'unknown';
  }
}

return [{
  json: {
    _route: route,
    chat_id: Number(chat_id),
    first_name: first_name,
    telegram_id: telegram_id,
    username: username,
    callback_data: callback_data
  }
}];
